VALUES
  ('judicial-cf446b4c-moex-00454', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '民法第248條規定：「訂約當事人之一方，由他方受有定金時，推定其契約成立。」該定金之性 質為：', '["解約定金", "證約定金", "成約定金", "違約定金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00455', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於無因管理之類型，下列敘述，何者錯誤？', '["客觀上屬於他人事務，管理人有為他人管理事務之意思，不論管理是否有利於他人，屬適法無 因管理", "客觀上屬於他人事務，管理人主觀上知其所管理者，係他人事務，但無為他人管理事務之意思， 屬不法管理", "客觀上屬於他人事務，管理人主觀上不知其所管理者，係他人事務，且無為他人管理事務之意 思，屬誤信管理", "客觀上屬於自己事務，管理人主觀上誤以為係他人事務而管理，屬幻想管理 20420 20520"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00456', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲男之叔叔為乙，乙之配偶為丙。乙死亡後，甲與丙結婚，其效力如何？', '["有效", "得撤銷", "效力未定", "無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00457', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何種約定，民法未明定須依書面，始生效力？', '["夫妻冠姓之約定", "夫妻協議一定數額之自由處分金", "父母委託他人行使對其未成年子女監護之職務", "養父母與養子女合意終止收養契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00458', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲於生前作成遺囑，將自己所有之A屋遺贈於乙。嗣後，甲將A屋出售。甲死亡時，遺產僅有新 臺幣（下同）500萬元之存款。乙得否對甲之唯一繼承人丙請求相當於A屋之價值200萬元？', '["可，因丙應以遺產為限，對乙負清償責任", "可，遺贈因甲之死亡而生效", "不可，因甲出售A屋，視為撤回遺贈", "不可，因遺贈債務之給付不能係不可歸責於丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00459', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲乙為夫妻。有一子丙，一女丁。丙有戊、己、庚三子，丁有辛子。丁早逝。乙死亡時，下列敘 述，何者正確？', '["辛不得繼承", "辛得繼承乙五分之一的遺產", "辛得繼承乙四分之一的遺產", "辛得繼承乙三分之一的遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00460', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲男與乙女結婚，婚後生子丙。嗣後因甲男與乙女離婚，乙女再與丁女於戶政機關辦理結婚登記， 丁女依法收養丙男為養子，經過1年後，丁女死亡，其死亡前依法立有遺囑，將所有財產全數捐 贈社福團體。丁女死亡時，留有遺產新臺幣（下同）900 萬元，丁女有唯一親人戊妹。何人各有 特留分多少金額？', '["乙女、戊妹特留分各225萬元", "乙女、丙養子特留分各225萬元", "乙女、丙養子、戊妹特留分各150萬元", "乙女特留分225萬元、戊妹特留分150萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00461', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者得以事後拋棄？', '["親屬關係", "繼承權", "自由", "權利能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00462', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於法律行為之代理及代表之敘述，何者正確？', '["公司董事不問有無代表權，就其代表公司所為之任何法律行為，均屬有效", "甲請5歲兒童乙傳遞訊息，此兒童乙為甲之代理人", "占有輔助人為代理人之一種型態", "代理人不以有完全行為能力為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00463', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '於民國（下同）106年間，訂立租賃契約，約定：「租賃期間自107年6月1日起，租期2年」， 該租賃關係何時終了？', '["109年5月30日", "109年5月31日", "109年6月1日", "109年6月2日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
